import React, { useState } from 'react';
import { BioData } from '../types';
import { generateBioSummary } from '../services/geminiService';
import { Sparkles, Loader2, Plus, Trash2, Upload } from 'lucide-react';

interface Props {
  data: BioData;
  onChange: (data: BioData) => void;
}

export const BioDataForm: React.FC<Props> = ({ data, onChange }) => {
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleChange = (field: keyof BioData, value: string) => {
    onChange({ ...data, [field]: value });
  };

  const handleArrayChange = (field: 'education' | 'siblings', index: number, value: string) => {
    const newArray = [...data[field]];
    newArray[index] = value;
    onChange({ ...data, [field]: newArray });
  };

  const addItem = (field: 'education' | 'siblings') => {
    onChange({ ...data, [field]: [...data[field], ""] });
  };

  const removeItem = (field: 'education' | 'siblings', index: number) => {
    const newArray = [...data[field]];
    newArray.splice(index, 1);
    onChange({ ...data, [field]: newArray });
  };

  const handleGenerateSummary = async () => {
    setIsGenerating(true);
    setError(null);
    try {
      const summary = await generateBioSummary(data);
      onChange({ ...data, summary });
    } catch (e) {
      setError("Failed to generate summary. Ensure API Key is valid.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onChange({ ...data, imageUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="space-y-8 p-6 bg-white rounded-xl shadow-sm border border-slate-200">

      {/* Header for Form */}
      <div>
        <h2 className="text-2xl font-serif font-bold text-slate-800">Edit Details</h2>
        <p className="text-slate-500 text-sm">Update the information below to customize the PDF.</p>
      </div>

      {/* Profile Image */}
      <div className="flex items-center space-x-4">
        <div className="w-20 h-24 bg-slate-100 border border-slate-300 flex items-center justify-center overflow-hidden rounded">
          {data.imageUrl ? (
             <img src={data.imageUrl} alt="Preview" className="w-full h-full object-cover" />
          ) : (
             <span className="text-xs text-slate-400">No Photo</span>
          )}
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Profile Photo</label>
          <div className="flex items-center">
             <label htmlFor="photo-upload" className="cursor-pointer flex items-center space-x-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 text-sm rounded transition">
                <Upload className="w-4 h-4" />
                <span>Upload Photo</span>
             </label>
             <input 
                id="photo-upload" 
                type="file" 
                accept="image/*" 
                className="hidden" 
                onChange={handleImageUpload}
             />
             {data.imageUrl && (
                 <button onClick={() => onChange({...data, imageUrl: undefined})} className="ml-2 text-red-500 text-xs hover:underline">Remove</button>
             )}
          </div>
        </div>
      </div>

      {/* AI Summary Section */}
      <div className="bg-amber-50 p-4 rounded-lg border border-amber-200">
        <div className="flex justify-between items-center mb-2">
            <label className="block text-sm font-bold text-amber-900">Professional Summary</label>
            <button 
                onClick={handleGenerateSummary}
                disabled={isGenerating}
                className="flex items-center space-x-1 text-xs font-bold text-white bg-amber-600 hover:bg-amber-700 px-3 py-1 rounded-full transition disabled:opacity-50"
            >
                {isGenerating ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                <span>{isGenerating ? "Thinking..." : "Generate with AI"}</span>
            </button>
        </div>
        <textarea
            className="w-full p-2 text-sm border-amber-200 rounded focus:ring-amber-500 focus:border-amber-500 bg-white"
            rows={4}
            value={data.summary || ""}
            onChange={(e) => handleChange("summary", e.target.value)}
            placeholder="Click 'Generate with AI' to create a professional summary automatically..."
        />
        {error && <p className="text-xs text-red-600 mt-1">{error}</p>}
      </div>

      {/* Personal Details */}
      <FormSection title="Personal Information">
        <Input label="Full Name" value={data.name} onChange={(v) => handleChange("name", v)} />
        <div className="grid grid-cols-2 gap-4">
            <Input label="Date of Birth" value={data.dob} onChange={(v) => handleChange("dob", v)} />
            <Input label="Blood Group" value={data.bloodGroup} onChange={(v) => handleChange("bloodGroup", v)} />
        </div>
        <Input label="Place of Birth" value={data.placeOfBirth} onChange={(v) => handleChange("placeOfBirth", v)} />
        <div className="grid grid-cols-2 gap-4">
            <Input label="Height" value={data.height} onChange={(v) => handleChange("height", v)} />
            <Input label="Religion" value={data.religion} onChange={(v) => handleChange("religion", v)} />
        </div>
        <Input label="Occupation" value={data.occupation} onChange={(v) => handleChange("occupation", v)} />
      </FormSection>

      {/* Education */}
      <FormSection title="Education">
        {data.education.map((edu, idx) => (
            <div key={idx} className="flex gap-2 mb-2">
                <input 
                    className="flex-1 p-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-amber-500 focus:outline-none"
                    value={edu}
                    onChange={(e) => handleArrayChange('education', idx, e.target.value)}
                />
                <button onClick={() => removeItem('education', idx)} className="text-slate-400 hover:text-red-500">
                    <Trash2 className="w-4 h-4" />
                </button>
            </div>
        ))}
        <button onClick={() => addItem('education')} className="text-sm text-amber-600 font-medium flex items-center hover:text-amber-700">
            <Plus className="w-4 h-4 mr-1" /> Add Education
        </button>
      </FormSection>

      {/* Family */}
      <FormSection title="Family Details">
        <Input label="Father's Name" value={data.fatherName} onChange={(v) => handleChange("fatherName", v)} />
        <Input label="Father's Occupation" value={data.fatherOccupation} onChange={(v) => handleChange("fatherOccupation", v)} />
        <Input label="Mother's Name" value={data.motherName} onChange={(v) => handleChange("motherName", v)} />
        <Input label="Mother's Occupation" value={data.motherOccupation} onChange={(v) => handleChange("motherOccupation", v)} />

        <div className="mt-4">
            <label className="block text-sm font-medium text-slate-700 mb-2">Siblings</label>
            {data.siblings.map((sib, idx) => (
                <div key={idx} className="flex gap-2 mb-2">
                    <input 
                        className="flex-1 p-2 border border-slate-300 rounded text-sm focus:ring-2 focus:ring-amber-500 focus:outline-none"
                        value={sib}
                        onChange={(e) => handleArrayChange('siblings', idx, e.target.value)}
                    />
                     <button onClick={() => removeItem('siblings', idx)} className="text-slate-400 hover:text-red-500">
                        <Trash2 className="w-4 h-4" />
                    </button>
                </div>
            ))}
             <button onClick={() => addItem('siblings')} className="text-sm text-amber-600 font-medium flex items-center hover:text-amber-700">
                <Plus className="w-4 h-4 mr-1" /> Add Sibling
            </button>
        </div>
      </FormSection>

      {/* Contact */}
      <FormSection title="Contact Information">
        <Input label="Mobile Number" value={data.contactNumber} onChange={(v) => handleChange("contactNumber", v)} />
        <Input label="Address" value={data.address} onChange={(v) => handleChange("address", v)} />
      </FormSection>

    </div>
  );
};

const FormSection: React.FC<{ title: string; children: React.ReactNode }> = ({ title, children }) => (
    <div className="border-t border-slate-100 pt-6">
        <h3 className="text-lg font-bold text-slate-800 mb-4">{title}</h3>
        <div className="space-y-4">
            {children}
        </div>
    </div>
);

const Input: React.FC<{ label: string; value: string; onChange: (v: string) => void }> = ({ label, value, onChange }) => (
    <div>
        <label className="block text-sm font-medium text-slate-600 mb-1">{label}</label>
        <input 
            type="text" 
            className="w-full p-2 border border-slate-300 rounded focus:ring-2 focus:ring-amber-500 focus:outline-none transition-all text-slate-800"
            value={value}
            onChange={(e) => onChange(e.target.value)}
        />
    </div>
);

