import { GoogleGenAI } from "@google/genai";
import { BioData, SectionDetails, SectionList } from "../types";

const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

// Helper to find value by label across all sections
const findValue = (data: BioData, searchLabel: string): string => {
  for (const section of data.sections) {
    if (section.type === 'details') {
      const field = (section as SectionDetails).fields.find(f => f.label.toLowerCase().includes(searchLabel.toLowerCase()));
      if (field) return field.value;
    }
  }
  return "";
};

const getEducation = (data: BioData): string[] => {
  for (const section of data.sections) {
    if (section.type === 'list' && (section.title.toLowerCase().includes('education') || section.title.toLowerCase().includes('qualification'))) {
      return (section as SectionList).items;
    }
  }
  return [];
};

export const generateBioSummary = async (data: BioData): Promise<string> => {
  try {
    const ai = getAiClient();

    const name = findValue(data, "Name");
    const occupation = findValue(data, "Occupation");
    const fatherOcc = findValue(data, "Father's Occupation") || findValue(data, "Father");
    const motherOcc = findValue(data, "Mother's Occupation") || findValue(data, "Mother");
    const religion = findValue(data, "Religion");
    const education = getEducation(data);

    // Construct a prompt based on the available data
    const prompt = `
      Write a polite, professional, and elegant 3-4 sentence "About Me" or "Objective" summary suitable for a marriage or professional Bio Data document.

      Use the following details:
      Name: ${name}
      Occupation: ${occupation}
      Education: ${education.join(", ")}
      Family Background: Father is ${fatherOcc}, Mother is ${motherOcc}.
      Religion: ${religion}

      Tone: Respectful, traditional yet modern, humble.
      Do not include the raw data lists, just a cohesive narrative summary.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    return response.text || "Could not generate summary.";
  } catch (error) {
    console.error("Error generating summary:", error);
    throw error;
  }
};

import jsPDF from 'jspdf';
import { BioData, SectionDetails, SectionList } from '../types';

export const generatePDF = (data: BioData) => {
  const doc = new jsPDF({
    orientation: 'portrait',
    unit: 'mm',
    format: 'a4'
  });

  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();
  const margin = 15; // Reduced margin for compactness
  const contentWidth = pageWidth - (margin * 2);

  let yPos = margin;

  // -- Helper Functions --
  const checkPageBreak = (heightNeeded: number) => {
    if (yPos + heightNeeded > pageHeight - margin) {
      doc.addPage();
      yPos = margin;
      return true;
    }
    return false;
  };

  const drawLine = (y: number) => {
    doc.setDrawColor(217, 119, 6); // amber-600
    doc.setLineWidth(0.5);
    doc.line(margin, y, pageWidth - margin, y);
  };

  const addSectionTitle = (title: string, y: number) => {
    checkPageBreak(15);
    doc.setFont("times", "bold");
    doc.setFontSize(13); // Slightly smaller for compactness
    doc.setTextColor(30, 41, 59); // slate-800
    doc.text(title.toUpperCase(), margin, y);
    drawLine(y + 1.5);
    return y + 8;
  };

  const addField = (label: string, value: string, y: number, isLong = false): number => {
    doc.setFont("times", "bold");
    doc.setFontSize(10.5); // Compact font
    doc.setTextColor(71, 85, 105); // slate-600

    // Check height before rendering
    // Estimate height: usually 1 line (6mm) or more

    const labelWidth = 45;
    const valueX = margin + labelWidth;
    const maxValueWidth = contentWidth - labelWidth;

    doc.setFont("times", "normal"); // Switch to normal to calculate text size
    const splitTitle = doc.splitTextToSize(value, maxValueWidth);
    const heightNeeded = (splitTitle.length * 5) + 2; // Compact line height

    if (checkPageBreak(heightNeeded)) {
        y = yPos;
    }

    // Render Label
    doc.setFont("times", "bold");
    doc.setTextColor(71, 85, 105);
    doc.text(label + ":", margin, y);

    // Render Value
    doc.setFont("times", "normal");
    doc.setTextColor(15, 23, 42); // slate-900
    doc.text(splitTitle, valueX, y);

    return y + heightNeeded; 
  };

  // -- BORDER --
  doc.setDrawColor(217, 119, 6); // amber-600
  doc.setLineWidth(1);
  doc.rect(8, 8, pageWidth - 16, pageHeight - 16);

  doc.setDrawColor(30, 41, 59); // slate-800
  doc.setLineWidth(0.5);
  doc.rect(10, 10, pageWidth - 20, pageHeight - 20);

  // -- IMAGE (Centered Top) --
  if (data.imageUrl) {
     try {
        const imgSize = 35; // Size in mm (Compact)
        const xPos = (pageWidth - imgSize) / 2;
        doc.addImage(data.imageUrl, 'JPEG', xPos, yPos, imgSize, imgSize);
        yPos += imgSize + 5; 
     } catch (e) {
         console.warn("Could not add image to PDF", e);
     }
  } else {
      yPos += 5;
  }

  // -- HEADER --
  yPos += 8;
  doc.setFont("times", "bold");
  doc.setFontSize(22);
  doc.setTextColor(217, 119, 6); // amber-600
  doc.text("BIO DATA", pageWidth / 2, yPos, { align: "center" });

  yPos += 12;

  // -- SUMMARY --
  if (data.summary) {
    yPos = addSectionTitle("Professional Summary", yPos);
    doc.setFont("times", "italic");
    doc.setFontSize(10.5);
    const splitSummary = doc.splitTextToSize(data.summary, contentWidth);
    doc.text(splitSummary, margin, yPos);
    yPos += (splitSummary.length * 5) + 4;
  }

  // -- DYNAMIC SECTIONS --
  data.sections.forEach((section) => {
      // Skip empty sections? No, user might want to see headers. 
      // But for "deletable" requirement, if user deleted all fields, we assume they removed the section in the UI.
      // Here we render whatever is in the data.

      yPos = addSectionTitle(section.title, yPos);

      if (section.type === 'details') {
          const details = section as SectionDetails;
          details.fields.forEach(field => {
              if (field.value.trim()) { // Only print if has value
                  yPos = addField(field.label, field.value, yPos, field.value.length > 30);
              }
          });
      } else if (section.type === 'list') {
          const list = section as SectionList;
          doc.setFont("times", "normal");
          doc.setFontSize(10.5);
          doc.setTextColor(15, 23, 42);

          list.items.forEach(item => {
              if (item.trim()) {
                  const splitItem = doc.splitTextToSize("• " + item, contentWidth);
                  const height = splitItem.length * 5;
                  if (checkPageBreak(height)) {
                      yPos = addSectionTitle(section.title + " (Cont.)", yPos); // Re-add title if broken? Or just continue
                      // Actually addSectionTitle advances Y, so we just continue text
                  }
                  doc.text(splitItem, margin, yPos);
                  yPos += height + 1; // Small spacing
              }
          });
          yPos += 2;
      }

      yPos += 3; // Section spacing
  });

  // -- FOOTER --
  const today = new Date().toLocaleDateString();
  doc.setFontSize(8);
  doc.setTextColor(150);
  doc.text(`Generated on: ${today}`, margin, pageHeight - 12);

  // Find name for filename
  let filename = "BioData";
  for(const s of data.sections) {
      if(s.type === 'details') {
          const nameField = (s as SectionDetails).fields.find(f => f.label.toLowerCase() === 'name');
          if(nameField) filename = nameField.value.replace(/\s+/g, '_');
      }
  }

  doc.save(`${filename}_BioData.pdf`);
};

import React, { useState } from 'react';
import { BioData, Section, SectionDetails, SectionList, Field } from '../types';
import { generateBioSummary } from '../services/geminiService';
import { Sparkles, Loader2, Plus, Trash2, Upload, GripVertical, X } from 'lucide-react';

interface Props {
  data: BioData;
  onChange: (data: BioData) => void;
}

export const BioDataForm: React.FC<Props> = ({ data, onChange }) => {
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // -- Top Level Handlers --

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onChange({ ...data, imageUrl: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateSummary = async () => {
    setIsGenerating(true);
    setError(null);
    try {
      const summary = await generateBioSummary(data);
      onChange({ ...data, summary });
    } catch (e) {
      setError("Failed to generate summary. Ensure API Key is valid.");
    } finally {
      setIsGenerating(false);
    }
  };

  // -- Section Handlers --

  const addSection = (type: 'details' | 'list') => {
    const newSection: Section = type === 'details' 
      ? { id: Date.now().toString(), title: "New Section", type: 'details', fields: [] }
      : { id: Date.now().toString(), title: "New List", type: 'list', items: [] };

    onChange({ ...data, sections: [...data.sections, newSection] });
  };

  const removeSection = (index: number) => {
    const newSections = [...data.sections];
    newSections.splice(index, 1);
    onChange({ ...data, sections: newSections });
  };

  const updateSectionTitle = (index: number, title: string) => {
    const newSections = [...data.sections];
    newSections[index] = { ...newSections[index], title };
    onChange({ ...data, sections: newSections });
  };

  // -- Field/Item Handlers --

  const addField = (sectionIndex: number) => {
    const newSections = [...data.sections];
    const section = newSections[sectionIndex] as SectionDetails;
    section.fields.push({ id: Date.now().toString(), label: "New Label", value: "" });
    onChange({ ...data, sections: newSections });
  };

  const removeField = (sectionIndex: number, fieldIndex: number) => {
    const newSections = [...data.sections];
    const section = newSections[sectionIndex] as SectionDetails;
    section.fields.splice(fieldIndex, 1);
    onChange({ ...data, sections: newSections });
  };

  const updateField = (sectionIndex: number, fieldIndex: number, key: 'label' | 'value', val: string) => {
    const newSections = [...data.sections];
    const section = newSections[sectionIndex] as SectionDetails;
    section.fields[fieldIndex] = { ...section.fields[fieldIndex], [key]: val };
    onChange({ ...data, sections: newSections });
  };

  const addListItem = (sectionIndex: number) => {
    const newSections = [...data.sections];
    const section = newSections[sectionIndex] as SectionList;
    section.items.push("");
    onChange({ ...data, sections: newSections });
  };

  const removeListItem = (sectionIndex: number, itemIndex: number) => {
    const newSections = [...data.sections];
    const section = newSections[sectionIndex] as SectionList;
    section.items.splice(itemIndex, 1);
    onChange({ ...data, sections: newSections });
  };

  const updateListItem = (sectionIndex: number, itemIndex: number, val: string) => {
    const newSections = [...data.sections];
    const section = newSections[sectionIndex] as SectionList;
    section.items[itemIndex] = val;
    onChange({ ...data, sections: newSections });
  };

  return (
    <div className="space-y-8 p-6 bg-white rounded-xl shadow-sm border border-slate-200">

      {/* Header */}
      <div>
        <h2 className="text-2xl font-serif font-bold text-slate-800">Edit Details</h2>
        <p className="text-slate-500 text-sm">Customize fields, labels, and content. Add or remove sections as needed.</p>
      </div>

      {/* Image Upload */}
      <div className="flex items-center space-x-4">
        <div className="w-24 h-24 bg-slate-100 border border-slate-300 flex items-center justify-center overflow-hidden rounded">
          {data.imageUrl ? (
             <img src={data.imageUrl} alt="Preview" className="w-full h-full object-cover" />
          ) : (
             <span className="text-xs text-slate-400">No Photo</span>
          )}
        </div>
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Profile Photo</label>
          <div className="flex items-center">
             <label htmlFor="photo-upload" className="cursor-pointer flex items-center space-x-2 px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 text-sm rounded transition">
                <Upload className="w-4 h-4" />
                <span>Upload Photo</span>
             </label>
             <input 
                id="photo-upload" 
                type="file" 
                accept="image/*" 
                className="hidden" 
                onChange={handleImageUpload}
             />
             {data.imageUrl && (
                 <button onClick={() => onChange({...data, imageUrl: undefined})} className="ml-2 text-red-500 text-xs hover:underline">Remove</button>
             )}
          </div>
        </div>
      </div>

      {/* Summary */}
      <div className="bg-amber-50 p-4 rounded-lg border border-amber-200">
        <div className="flex justify-between items-center mb-2">
            <label className="block text-sm font-bold text-amber-900">Professional Summary</label>
            <button 
                onClick={handleGenerateSummary}
                disabled={isGenerating}
                className="flex items-center space-x-1 text-xs font-bold text-white bg-amber-600 hover:bg-amber-700 px-3 py-1 rounded-full transition disabled:opacity-50"
            >
                {isGenerating ? <Loader2 className="w-3 h-3 animate-spin" /> : <Sparkles className="w-3 h-3" />}
                <span>{isGenerating ? "Thinking..." : "Generate with AI"}</span>
            </button>
        </div>
        <textarea
            className="w-full p-2 text-sm border-amber-200 rounded focus:ring-amber-500 focus:border-amber-500 bg-white"
            rows={4}
            value={data.summary || ""}
            onChange={(e) => onChange({ ...data, summary: e.target.value })}
            placeholder="Click 'Generate with AI' to create a summary..."
        />
        {error && <p className="text-xs text-red-600 mt-1">{error}</p>}
      </div>

      {/* Sections */}
      <div className="space-y-6">
        {data.sections.map((section, sIdx) => (
          <div key={section.id} className="border border-slate-200 rounded-lg p-4 bg-slate-50 relative group">

            {/* Section Header */}
            <div className="flex items-center justify-between mb-4">
              <input 
                value={section.title}
                onChange={(e) => updateSectionTitle(sIdx, e.target.value)}
                className="text-lg font-bold text-slate-800 bg-transparent border-b border-transparent hover:border-slate-300 focus:border-amber-500 focus:outline-none transition-colors w-full mr-4"
              />
              <button 
                onClick={() => removeSection(sIdx)}
                className="text-slate-400 hover:text-red-500 transition-colors p-1"
                title="Delete Section"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>

            {/* Section Content */}
            <div className="space-y-2">
              {section.type === 'details' ? (
                <>
                  {(section as SectionDetails).fields.map((field, fIdx) => (
                    <div key={field.id} className="flex gap-2 items-start group/field">
                       <div className="w-1/3">
                          <input 
                            value={field.label}
                            onChange={(e) => updateField(sIdx, fIdx, 'label', e.target.value)}
                            className="w-full p-2 text-xs font-bold text-slate-600 bg-white border border-slate-200 rounded focus:border-amber-500 focus:outline-none"
                            placeholder="Label"
                          />
                       </div>
                       <div className="flex-1">
                          <input 
                            value={field.value}
                            onChange={(e) => updateField(sIdx, fIdx, 'value', e.target.value)}
                            className="w-full p-2 text-sm text-slate-800 bg-white border border-slate-200 rounded focus:border-amber-500 focus:outline-none"
                            placeholder="Value"
                          />
                       </div>
                       <button 
                         onClick={() => removeField(sIdx, fIdx)}
                         className="text-slate-300 hover:text-red-500 p-2 opacity-0 group-hover/field:opacity-100 transition-opacity"
                       >
                         <X className="w-4 h-4" />
                       </button>
                    </div>
                  ))}
                  <button 
                    onClick={() => addField(sIdx)}
                    className="text-xs text-amber-600 font-bold hover:text-amber-700 flex items-center mt-2"
                  >
                    <Plus className="w-3 h-3 mr-1" /> Add Field
                  </button>
                </>
              ) : (
                <>
                  {(section as SectionList).items.map((item, iIdx) => (
                    <div key={iIdx} className="flex gap-2 items-center group/item">
                       <span className="text-slate-400">•</span>
                       <input 
                          value={item}
                          onChange={(e) => updateListItem(sIdx, iIdx, e.target.value)}
                          className="flex-1 p-2 text-sm text-slate-800 bg-white border border-slate-200 rounded focus:border-amber-500 focus:outline-none"
                          placeholder="Item description..."
                       />
                       <button 
                         onClick={() => removeListItem(sIdx, iIdx)}
                         className="text-slate-300 hover:text-red-500 p-2 opacity-0 group-hover/item:opacity-100 transition-opacity"
                       >
                         <X className="w-4 h-4" />
                       </button>
                    </div>
                  ))}
                   <button 
                    onClick={() => addListItem(sIdx)}
                    className="text-xs text-amber-600 font-bold hover:text-amber-700 flex items-center mt-2"
                  >
                    <Plus className="w-3 h-3 mr-1" /> Add Item
                  </button>
                </>
              )}
            </div>

          </div>
        ))}
      </div>

      {/* Add Section Buttons */}
      <div className="flex gap-4 pt-4 border-t border-slate-100">
        <button 
          onClick={() => addSection('details')}
          className="flex-1 py-3 border-2 border-dashed border-slate-300 rounded-lg text-slate-500 font-bold hover:border-amber-500 hover:text-amber-600 transition flex justify-center items-center gap-2"
        >
          <Plus className="w-5 h-5" /> Add Details Section
        </button>
        <button 
          onClick={() => addSection('list')}
          className="flex-1 py-3 border-2 border-dashed border-slate-300 rounded-lg text-slate-500 font-bold hover:border-amber-500 hover:text-amber-600 transition flex justify-center items-center gap-2"
        >
          <Plus className="w-5 h-5" /> Add List Section
        </button>
      </div>

    </div>
  );
};

